PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?attendance
WHERE {
  VALUES ?series { wd:Q3511178 wd:Q14870260 wd:Q56692089 }
  ?game wdt:P1545 ?series ;
        wdt:P1346 wd:Q1825 ;
        wdt:P1110 ?attendance .
  FILTER (isNumeric(?attendance))
}
ORDER BY ASC(?attendance)
OFFSET 1
LIMIT 1

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT DISTINCT ?attendance
WHERE {
  VALUES ?series { wd:Q3511178 wd:Q14870260 wd:Q56692089 }
  ?game wdt:P1545 ?series ;
        wdt:P1344 wd:Q1825 ;
        wdt:P1110 ?attendance .
  FILTER (isNumeric(?attendance))
}
ORDER BY ASC(?attendance)
OFFSET 1
LIMIT 1
